mapper.select:
SELECT A.FILE_ID , A.REF_TYPE , A.REF_ID , A.ORIGIN_NAME , A.SAVED_NAME , A.FILE_PATH , A.EXTENSION , A.FILE_SIZE , A.CONTENT_TYPE , A.DOWNLOAD_COUNT , A.DEL_YN FROM FILE_INFO A
AND DEL_YN = 'N'
AND A.REF_TYPE = #{refType}
AND A.REF_ID = #{refId}
ORDER BY A.FILE_ID DESC, A.ORIGIN_NAME

mapper.insert:
INSERT INTO FILE_INFO (
REF_TYPE
, REF_ID
, ORIGIN_NAME
, SAVED_NAME
, FILE_PATH
, EXTENSION
, FILE_SIZE
, CONTENT_TYPE
, DOWNLOAD_COUNT
, DEL_YN

)
VALUES (
#{refType}
, #{refId}
, #{originName}
, #{savedName}
, #{filePath}
, #{extension}
, #{fileSize}
, #{contentType}
, #{downloadCount}
, #{delYn}

)

mapper.update:
UPDATE FILE_INFO
SET REF_ID = #{refId}

WHERE FILE_ID = #{fileId}

UPDATE FILE_INFO
SET DEL_YN = #{delYn}

WHERE FILE_ID = #{fileId}

UPDATE FILE_INFO
SET DOWNLOAD_COUNT = DOWNLOAD_COUNT + 1
WHERE FILE_ID = #{fileId}
